"""ETA prediction Pydantic data models."""

from datetime import datetime

from pydantic import BaseModel


class ETAPrediction(BaseModel):
    """An ETA prediction generated by the ETA predictor service."""

    model_config = {"protected_namespaces": ()}

    shipment_id: str
    predicted_arrival: datetime
    confidence_low: datetime
    confidence_high: datetime
    model_version: str
